/* global console, process */
import { spawn } from 'node:child_process';
import { existsSync } from 'node:fs';
import { performance } from 'node:perf_hooks';
import { fileURLToPath } from 'node:url';
import path from 'node:path';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const gnosisDir = path.resolve(__dirname, '../..');
const monsterPath = path.resolve(gnosisDir, 'polyglot/target/release/monster');
const gnexecPath = path.resolve(gnosisDir, 'polyglot/target/release/gnexec');
const monsterRuntimePath = existsSync(monsterPath) ? monsterPath : gnexecPath;

if (!existsSync(monsterRuntimePath)) {
  console.error(`Monster runtime not found at ${monsterRuntimePath}`);
  process.exit(1);
}

const testUserIds = Array.from({ length: 100 }, (_, i) => `user${i}`);

function percentile(sorted, ratio) {
  if (sorted.length === 0) return 0;
  const index = Math.min(
    sorted.length - 1,
    Math.max(0, Math.floor(sorted.length * ratio))
  );
  return sorted[index] ?? 0;
}

function summarize(latencies) {
  const sorted = [...latencies].sort((a, b) => a - b);
  const sum = sorted.reduce((acc, v) => acc + v, 0);
  return {
    count: sorted.length,
    p50_us: percentile(sorted, 0.50),
    p95_us: percentile(sorted, 0.95),
    p99_us: percentile(sorted, 0.99),
    max_us: sorted[sorted.length - 1] ?? 0,
    mean_us: sum / Math.max(1, sorted.length),
  };
}

async function runMonsterResident(requests, env = {}) {
  return new Promise((resolve, reject) => {
    const child = spawn(monsterRuntimePath, [
      '--resident-jsonl',
      path.resolve(__dirname, 'fanout.ts'),
    ], {
      env: { ...process.env, ...env },
      stdio: ['pipe', 'pipe', 'pipe'],
    });

    const results = [];
    let stderr = '';

    child.stdout.setEncoding('utf8');
    child.stderr.setEncoding('utf8');

    child.stdout.on('data', (chunk) => {
      chunk.trim().split('\n').forEach(line => {
        if (line) {
          try {
            const obj = JSON.parse(line);
            if (obj.ok && obj.elapsed_ns !== undefined) {
              results.push(obj.elapsed_ns / 1000); // Convert ns to µs
            }
          } catch (e) {
            // Ignore parse errors
          }
        }
      });
    });

    child.stderr.on('data', (chunk) => {
      stderr += chunk;
    });

    child.on('error', reject);
    child.on('close', (code) => {
      if (code !== 0 && stderr) {
        reject(new Error(`Process exited with code ${code}: ${stderr}`));
      } else {
        resolve(results);
      }
    });

    // Send requests
    setImmediate(() => {
      requests.forEach((userId, index) => {
        const line = JSON.stringify({ userId, index });
        child.stdin.write(line + '\n');
      });
      child.stdin.end();
    });
  });
}

/**
 * Dynamic ramp: start at 1 request, double until we hit a ceiling or break.
 * Measure at each ramp level to find the Reynolds number breakpoint.
 *
 * Reynolds analogy:
 * - Low Re: laminar flow (serial, gates help)
 * - High Re: turbulent flow (concurrent, gates essential)
 * - Breakpoint: where behavior shifts (p99 multiplier changes slope)
 */
async function runDynamicRamp(naive = false) {
  const label = naive ? '[NAIVE]' : '[HELIX]';
  console.log(`\n🌊 DYNAMIC RAMP ${label} — finding Reynolds number breakpoint`);
  console.log('='.repeat(70));
  console.log('Load Level | Requests | p50 µs | p99 µs | max µs | Multiplier | Phase');
  console.log('-'.repeat(70));

  const env = naive ? { FOIL_NAIVE: '1' } : {};
  const results = [];

  // Start at 1, double each iteration: 1, 2, 4, 8, 16, 32, 64, 128, 256, 512, 1024, 2048, 4096, 8192
  let requestCount = 1;
  let previousP99 = 0;
  let saturationThreshold = null;

  while (requestCount <= 8192) {
    const requests = Array.from({ length: requestCount }, (_, i) =>
      testUserIds[i % testUserIds.length]
    );

    const latencies = await runMonsterResident(requests, env);
    const stats = summarize(latencies);

    // Calculate p99 multiplier (how many service times did p99 expand?)
    const p99Multiplier = stats.p99_us / stats.mean_us; // Rough approximation

    // Detect phase transition: where does slope change?
    let phase = 'laminar';
    if (previousP99 > 0) {
      const slope = stats.p99_us / previousP99;
      if (slope > 1.5) {
        phase = '⚠️ transitioning';
        if (!saturationThreshold) saturationThreshold = requestCount;
      } else if (slope > 2.0) {
        phase = '🔴 turbulent';
      }
    }
    previousP99 = stats.p99_us;

    results.push({
      requestCount,
      stats,
      p99Multiplier,
      phase,
    });

    console.log(
      `${requestCount.toString().padStart(10)} | ` +
      `${stats.count.toString().padStart(8)} | ` +
      `${stats.p50_us.toFixed(0).padStart(6)} | ` +
      `${stats.p99_us.toFixed(0).padStart(6)} | ` +
      `${stats.max_us.toFixed(0).padStart(6)} | ` +
      `${p99Multiplier.toFixed(2).padStart(10)} | ` +
      `${phase.padStart(15)}`
    );

    requestCount *= 2;
  }

  return { results, saturationThreshold };
}

async function main() {
  console.log('🌊 Monster HELIX Ramp — Dynamic Load Onramp & Reynolds Breakpoint');
  console.log('==================================================================\n');
  console.log('Finds the Reynolds number (Re) where the system transitions from');
  console.log('laminar (serial) to turbulent (concurrent) behavior.\n');

  try {
    const naiveRamp = await runDynamicRamp(true);
    const helixRamp = await runDynamicRamp(false);

    console.log('\n' + '='.repeat(70));
    console.log('REYNOLDS NUMBER ANALYSIS');
    console.log('='.repeat(70));

    if (naiveRamp.saturationThreshold) {
      console.log(`\nNAIVE — Saturation threshold: ${naiveRamp.saturationThreshold} requests`);
    }
    if (helixRamp.saturationThreshold) {
      console.log(`HELIX — Saturation threshold: ${helixRamp.saturationThreshold} requests`);
    }

    // Find knees in the curve
    console.log('\nPhase transitions detected:');
    naiveRamp.results.forEach((r) => {
      if (r.phase !== 'laminar') {
        console.log(`  NAIVE @ ${r.requestCount.toString().padStart(5)} reqs: ${r.phase} (p99=${r.stats.p99_us.toFixed(0)} µs)`);
      }
    });
    helixRamp.results.forEach((r) => {
      if (r.phase !== 'laminar') {
        console.log(`  HELIX @ ${r.requestCount.toString().padStart(5)} reqs: ${r.phase} (p99=${r.stats.p99_us.toFixed(0)} µs)`);
      }
    });

    process.exit(0);
  } catch (error) {
    console.error('Error:', error.message);
    process.exit(1);
  }
}

main();
